129	fn rbtdrd_build_run_lifecycle_impl(ctx: &mut rbtdri_Context, dir: &Path) -> rbtdre_Verdict {
130	    let vessel_dir = RBTDRC_BUSYBOX_VESSEL_DIR;
131	    if !ctx.project_root().join(vessel_dir).is_dir() {
132	        return rbtdre_Verdict::Fail(format!("vessel directory not found: {}", vessel_dir));
