150	    };
151	    let gar_root = match rbtdri_read_burv_fact(&ordain, RBTDRC_FACT_GAR_ROOT) {
152	        Ok(v) => v,
153	        Err(e) => return rbtdre_Verdict::Fail(format!("read gar_root fact: {}", e)),
154	    };
155	    let ark_stem = match rbtdri_read_burv_fact(&ordain, RBTDRC_FACT_ARK_STEM) {
156	        Ok(v) => v,
157	        Err(e) => return rbtdre_Verdict::Fail(format!("read ark_stem fact: {}", e)),
158	    };
159	    let _ = std::fs::write(dir.join("02-hallmark.txt"), &hallmark);
160	
161	    // The image ref summon pulls locally: <gar_root>/<ark_stem>/image:<hallmark>.
162	    // Same construction onboarding's conjure verification tail uses.
163	    let image_ref = format!(
164	        "{}/{}/{}:{}",
165	        gar_root, ark_stem, RBTDRC_ARK_BASENAME_IMAGE, hallmark
166	    );
167	    let _ = std::fs::write(dir.join("02-image-ref.txt"), &image_ref);
168	
169	    // Summon: retriever pulls the hallmark's arks locally. Confirm the image
170	    // ark is resolvable before attempting to run it.
171	    let _ = std::fs::write(dir.join("03-summon.txt"), "summoning");
172	    let summon = match rbtdri_invoke_global(ctx, RBTDRM_COLOPHON_SUMMON, &[&hallmark], &[]) {
173	        Ok(r) if r.exit_code == 0 => r,
174	        Ok(r) => {
175	            return rbtdre_Verdict::Fail(format!("summon failed (exit {})\n{}", r.exit_code, r.stderr))
176	        }
177	        Err(e) => return rbtdre_Verdict::Fail(format!("summon invocation: {}", e)),
178	    };
179	    let _ = std::fs::write(dir.join("03-summon-stdout.txt"), &summon.stdout);
180	    if !rbtdrc_docker_inspect(&image_ref) {
181	        return rbtdre_Verdict::Fail(format!(
182	            "summon: image ark not local after pull: {}",
183	            image_ref
184	        ));
185	    }
186	
187	    // Bare run — the executability proof. No crucible: a plain
188	    // `<runtime> run --rm <ref> true` exiting 0 proves the summoned artifact
189	    // is runnable.
190	    let _ = std::fs::write(dir.join("04-run.txt"), "running degenerate command");
191	    if let Err(e) = rbtdrd_runtime_run(&image_ref, RBTDRD_PROOF_CMD, dir) {
192	        return rbtdre_Verdict::Fail(format!("bare run executability proof: {}", e));
193	    }
194	
195	    // Abjure — remove the hallmark's arks, restoring the standing depot to its
196	    // pre-run inventory. BURE_CONFIRM skipped for non-interactive teardown.
197	    let _ = std::fs::write(dir.join("05-abjure.txt"), "abjuring");
198	    match rbtdri_invoke_global(
199	        ctx,
200	        RBTDRM_COLOPHON_ABJURE,
201	        &[&hallmark],
202	        &[(RBTDRI_BURE_CONFIRM_KEY, RBTDRI_BURE_CONFIRM_SKIP)],
203	    ) {
204	        Ok(r) if r.exit_code == 0 => {}
205	        Ok(r) => {
206	            return rbtdre_Verdict::Fail(format!("abjure failed (exit {})\n{}", r.exit_code, r.stderr))
207	        }
208	        Err(e) => return rbtdre_Verdict::Fail(format!("abjure invocation: {}", e)),
209	    }
210	
211	    let _ = std::fs::write(dir.join("06-passed.txt"), "passed");
212	    rbtdre_Verdict::Pass
213	}
